#include <mpi.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * MPI Collective Communication Operations - C Implementation
 * 
 * Demonstrates:
 * - MPI_Barrier: Synchronization
 * - MPI_Bcast: Broadcast from root to all
 * - MPI_Scatter: Distribute chunks to all processes
 * - MPI_Gather: Collect data to root
 * - MPI_Reduce: Reduction operation (result to root)
 * - MPI_Allreduce: Reduction operation (result to all)
 * - MPI_Allgather: Gather and distribute to all
 */

#define MAX_PROCS 8

/* Helper function to print array */
void print_array(int *arr, int n, int rank, const char *label) {
 printf("Process %d: %s [", rank, label);
 for (int i = 0; i < n; i++) {
 printf("%d", arr[i]);
 if (i < n - 1) printf(", ");
 }
 printf("]\n");
}

/* Example 1: Basic Collective Operations */
void demonstrate_basic_collectives(int rank, int size) {
 int local_value = rank + 1; // 1, 2, 3, 4 for 4 processes
 int send_data[4] = {10, 20, 30, 40};
 int recv_data;
 int all_data[MAX_PROCS];
 int gather_data[MAX_PROCS];
 int result;

 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n=== Basic Collective Operations ===\n");
 MPI_Barrier(MPI_COMM_WORLD);

 /* 1. MPI_Bcast - Broadcast */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n1. MPI_Bcast (Broadcast from root 0):\n");
 MPI_Barrier(MPI_COMM_WORLD);

 // Root process has send_data, others have NULL
 int bcast_buffer[4];
 if (rank == 0) {
 memcpy(bcast_buffer, send_data, sizeof(send_data));
 }

 MPI_Bcast(bcast_buffer, 4, MPI_INT, 0, MPI_COMM_WORLD);
 print_array(bcast_buffer, 4, rank, "Broadcast");

 /* 2. MPI_Scatter - Distribute chunks */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n2. MPI_Scatter (Distribute chunks):\n");
 MPI_Barrier(MPI_COMM_WORLD);

 int scatter_send[MAX_PROCS * 2]; // 2 elements per process
 int scatter_recv[2];

 if (rank == 0) {
 // Create data: [0,1, 2,3, 4,5, 6,7] for 4 processes
 for (int i = 0; i < size * 2; i++) {
 scatter_send[i] = i;
 }
 }

 MPI_Scatter(scatter_send, 2, MPI_INT, 
 scatter_recv, 2, MPI_INT, 
 0, MPI_COMM_WORLD);

 printf("Process %d: Scatter recv = [%d, %d]\n", 
 rank, scatter_recv[0], scatter_recv[1]);

 /* 3. MPI_Gather - Collect to root */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n3. MPI_Gather (Collect to root):\n");
 MPI_Barrier(MPI_COMM_WORLD);

 int gather_send = rank * 100; // 0, 100, 200, 300
 int gather_recv[MAX_PROCS];

 MPI_Gather(&gather_send, 1, MPI_INT,
 gather_recv, 1, MPI_INT,
 0, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Process 0: Gathered data = [");
 for (int i = 0; i < size; i++) {
 printf("%d", gather_recv[i]);
 if (i < size - 1) printf(", ");
 }
 printf("]\n");
 }

 /* 4. MPI_Reduce - Reduction to root */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n4. MPI_Reduce (Sum to root):\n");
 MPI_Barrier(MPI_COMM_WORLD);

 int reduce_send = local_value; // 1, 2, 3, 4
 int reduce_result;

 MPI_Reduce(&reduce_send, &reduce_result, 1, MPI_INT, MPI_SUM, 0, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Process 0: Sum of 1+2+3+4 = %d\n", reduce_result);
 }

 /* 5. MPI_Allreduce - Reduction to all */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n5. MPI_Allreduce (All processes get result):\n");
 MPI_Barrier(MPI_COMM_WORLD);

 int allreduce_result;
 MPI_Allreduce(&reduce_send, &allreduce_result, 1, MPI_INT, MPI_SUM, MPI_COMM_WORLD);

 printf("Process %d: Allreduce sum = %d\n", rank, allreduce_result);

 /* 6. MPI_Allgather - Gather to all */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n6. MPI_Allgather (All get all data):\n");
 MPI_Barrier(MPI_COMM_WORLD);

 int allgather_send = rank + 100; // 100, 101, 102, 103
 int allgather_recv[MAX_PROCS];

 MPI_Allgather(&allgather_send, 1, MPI_INT,
 allgather_recv, 1, MPI_INT,
 MPI_COMM_WORLD);

 printf("Process %d: Allgathered = [", rank);
 for (int i = 0; i < size; i++) {
 printf("%d", allgather_recv[i]);
 if (i < size - 1) printf(", ");
 }
 printf("]\n");
}

/* Example 2: Practical Application - Parallel Sum Reduction */
void parallel_sum_reduction(int rank, int size) {
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n=== Practical: Parallel Sum Reduction ===\n");
 MPI_Barrier(MPI_COMM_WORLD);

 // Each process computes partial sum
 int local_start = rank * 10 + 1; // 1, 11, 21, 31
 int local_end = (rank + 1) * 10; // 10, 20, 30, 40
 int local_sum = 0;

 for (int i = local_start; i <= local_end; i++) {
 local_sum += i;
 }

 printf("Process %d: local_sum of %d-%d = %d\n", 
 rank, local_start, local_end, local_sum);

 // Global reduction
 int global_sum;
 MPI_Reduce(&local_sum, &global_sum, 1, MPI_INT, MPI_SUM, 0, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Process 0: Total sum = %d\n", global_sum);
 printf("Verification: 1+2+...+40 = %d\n", 40*41/2);
 }
}

/* Example 3: Practical Application - Finding Global Max */
void parallel_max_finding(int rank, int size) {
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n=== Practical: Finding Global Maximum ===\n");
 MPI_Barrier(MPI_COMM_WORLD);

 // Each process has random local maximum
 int local_values[3] = {rank * 10 + 1, rank * 10 + 5, rank * 10 + 3};
 int local_max = local_values[0];
 for (int i = 1; i < 3; i++) {
 if (local_values[i] > local_max) local_max = local_values[i];
 }

 printf("Process %d: local_max = %d\n", rank, local_max);

 // Find global maximum using MPI_MAX
 int global_max;
 MPI_Reduce(&local_max, &global_max, 1, MPI_INT, MPI_MAX, 0, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Process 0: Global maximum = %d\n", global_max);
 }

 // Using Allreduce - all processes get the result
 int global_max_all;
 MPI_Allreduce(&local_max, &global_max_all, 1, MPI_INT, MPI_MAX, MPI_COMM_WORLD);
 printf("Process %d: Allreduce MAX = %d\n", rank, global_max_all);
}

/* Example 4: Practical Application - Parallel Matrix-Vector Multiply */
void parallel_matrix_vector(int rank, int size) {
 const int N = 8; // Matrix size
 const int local_rows = N / size; // Rows per process

 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) printf("\n=== Practical: Parallel Matrix-Vector Multiply ===\n");
 MPI_Barrier(MPI_COMM_WORLD);

 // Allocate local data
 double *local_matrix = malloc(local_rows * N * sizeof(double));
 double *vector = malloc(N * sizeof(double));
 double *local_result = malloc(local_rows * sizeof(double));

 // Root initializes matrix and vector
 if (rank == 0) {
 printf("Matrix-Vector multiplication with %d processes\n", size);
 printf("Each process handles %d rows\n", local_rows);
 }

 // Broadcast vector to all processes
 MPI_Bcast(vector, N, MPI_DOUBLE, 0, MPI_COMM_WORLD);

 // Root scatters matrix rows
 double *full_matrix = NULL;
 if (rank == 0) {
 full_matrix = malloc(N * N * sizeof(double));
 // Initialize with test data
 for (int i = 0; i < N * N; i++) {
 full_matrix[i] = 1.0; // Simple test: all ones
 }
 }

 MPI_Scatter(full_matrix, local_rows * N, MPI_DOUBLE,
 local_matrix, local_rows * N, MPI_DOUBLE,
 0, MPI_COMM_WORLD);

 // Each process computes its portion: y = A * x
 for (int i = 0; i < local_rows; i++) {
 local_result[i] = 0.0;
 for (int j = 0; j < N; j++) {
 local_result[i] += local_matrix[i * N + j] * vector[j];
 }
 }

 // Gather results at root
 double *final_result = NULL;
 if (rank == 0) {
 final_result = malloc(N * sizeof(double));
 }

 MPI_Gather(local_result, local_rows, MPI_DOUBLE,
 final_result, local_rows, MPI_DOUBLE,
 0, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Result vector: [");
 for (int i = 0; i < N; i++) {
 printf("%.1f", final_result[i]);
 if (i < N - 1) printf(", ");
 }
 printf("]\n");
 free(full_matrix);
 free(final_result);
 }

 // Cleanup
 free(local_matrix);
 free(vector);
 free(local_result);
}

int main(int argc, char *argv[]) {
 int rank, size;

 /* Initialize MPI */
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 printf("Process %d of %d starting...\n", rank, size);

 /* Demonstrate basic collective operations */
 demonstrate_basic_collectives(rank, size);

 /* Practical Example 1: Parallel Sum */
 parallel_sum_reduction(rank, size);

 /* Practical Example 2: Global Maximum */
 parallel_max_finding(rank, size);

 /* Practical Example 3: Matrix-Vector Multiplication */
 parallel_matrix_vector(rank, size);

 /* Final synchronization */
 MPI_Barrier(MPI_COMM_WORLD);
 if (rank == 0) {
 printf("\n=== All demonstrations complete! ===\n");
 }

 MPI_Finalize();
 return 0;
}

/*
 * COMPILATION AND RUN:
 * 
 * Compile: mpicc -o mpi_collective mpi_collective.c -lm
 * 
 * Run with 4 processes:
 * mpiexec -n 4 ./mpi_collective
 * 
 * Expected output demonstrates all collective operations:
 * - Broadcast: all processes receive [10, 20, 30, 40]
 * - Scatter: each process gets 2 elements
 * - Gather: root collects all values
 * - Reduce: sum of 1+2+3+4 = 10
 * - Allreduce: all processes see sum = 10
 * - Allgather: all processes see all gathered values
 */
